let searchData=[];async function getSearchData(){if(searchData.length>0)return searchData;try{const e=await fetch("/index.json");if(e.ok)return searchData=await e.json(),searchData}catch{console.log("index.json 不存在，使用页面内数据")}return searchData=Array.from(document.querySelectorAll("a")).filter(e=>e.href&&!e.href.includes("javascript")&&e.href.startsWith("/")).map(e=>({title:e.textContent.trim(),url:e.href,date:"",summary:""})).filter(e=>e.title.length>0&&e.title.length<100),searchData}function performSearch(e){const t=document.getElementById("searchResults");if(!t)return;if(!e||e.trim().length===0){t.innerHTML='<div class="search-hint">输入关键词搜索文章...</div>';return}const n=e.toLowerCase(),s=searchData.filter(e=>e.title.toLowerCase().includes(n)||e.summary&&e.summary.toLowerCase().includes(n));if(s.length===0){t.innerHTML='<div class="search-result-empty">没有找到相关文章</div>';return}t.innerHTML=s.slice(0,10).map(e=>`
        <a href="${e.url}" class="search-result-item">
            <div class="search-result-title">${escapeHtml(e.title)}</div>
            ${e.date?`<div class="search-result-date">${e.date}</div>`:""}
            ${e.summary?`<div class="search-result-summary">${escapeHtml(e.summary)}</div>`:""}
        </a>
    `).join("")}function escapeHtml(e){const t=document.createElement("div");return t.textContent=e,t.innerHTML}function initSearch(){const n=document.querySelector(".search-toggle"),e=document.getElementById("searchOverlay"),t=document.getElementById("searchInput"),s=document.getElementById("searchClose"),o=document.getElementById("searchResults");if(!n||!e||!t||!s)return;n.addEventListener("click",async n=>{n.preventDefault(),e.classList.add("active"),t.value="",t.focus(),o&&(o.innerHTML='<div class="search-hint">输入关键词搜索文章...</div>'),await getSearchData(),document.body.style.overflow="hidden"}),s.addEventListener("click",()=>{e.classList.remove("active"),document.body.style.overflow=""}),e.addEventListener("click",t=>{t.target===e&&(e.classList.remove("active"),document.body.style.overflow="")}),document.addEventListener("keydown",t=>{t.key==="Escape"&&e.classList.contains("active")&&(e.classList.remove("active"),document.body.style.overflow="")}),t.addEventListener("input",e=>{performSearch(e.target.value)})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",initSearch):initSearch()